function reverseBits(n) {
  let result = 0;
  for (let i = 0; i < 32; i++) {
    // Shift result left to make room for the next bit
    result = (result << 1) | (n & 1);
    // Shift n right to process the next bit
    n = n >>> 1;
  }
  // Use unsigned right shift by 0 to convert to unsigned 32-bit integer
  return result >>> 0;
}

